static void shell_execute_line(char *line) {
    if (!line || token_is_empty(line)) return;

    char *p = line;
    char *cmd = next_token(&p);
    if (!cmd) return;

    if (strcmp(cmd, "help") == 0) {
        cmd_help();
    } else if (strcmp(cmd, "ping") == 0) {
        cmd_ping();
    } else if (strcmp(cmd, "echo") == 0) {
        cmd_echo(next_token(&p));
    } else if (strcmp(cmd, "dump_memory") == 0) {
        cmd_dump_memory(next_token(&p), next_token(&p));
    } else if (strcmp(cmd, "read_flash") == 0) {
        cmd_read_flash(next_token(&p), next_token(&p));
    } else if (strcmp(cmd, "get_config") == 0) {
        cmd_get_config();
    } else if (strcmp(cmd, "jtag") == 0) {
        cmd_jtag(next_token(&p));
    } else if (strcmp(cmd, "reboot") == 0) {
        cmd_reboot();
    } else {
        con_write("\r\nERR unknown cmd\r\n");
    }
}

static void shell_on_rx_char(uint8_t b) {
    g_console.last_activity_ms = plat_millis();

    if (g_console.echo) {
        if (b == '\n') {
            con_write("\r\n");
        } else if (b == '\r') {
            con_write("\r\n");
        } else {
            con_putc((char)b);
        }
        con_flush();
    }

    if (b == '\r' || b == '\n') {
        if (g_console.rx_len >= sizeof(g_console.rx_line)) {
            g_console.rx_len = 0;
            con_write("\r\nERR line too long\r\n");
            con_prompt();
            return;
        }
        g_console.rx_line[g_console.rx_len] = '\0';

        if (g_console.rx_len > 0) {
            shell_execute_line(g_console.rx_line);
        }

        g_console.rx_len = 0;
        con_prompt();
        return;
    }

    if (b == 0x08 || b == 0x7F) { /* backspace/delete */
        if (g_console.rx_len > 0) {
            g_console.rx_len--;
            if (g_console.echo) {
                con_write("\b \b");
                con_flush();
            }
        }
        return;
    }

    if (isprint((int)b) || b == '\t') {
        if (g_console.rx_len < (sizeof(g_console.rx_line) - 1u)) {
            g_console.rx_line[g_console.rx_len++] = (char)b;
        } else {
            g_console.rx_len = 0;
            con_write("\r\nERR line too long\r\n");
            con_prompt();
        }
    }
}

