void diag_console_init(void) {
    memset(&g_console, 0, sizeof(g_console));
    g_console.echo = 1;
    plat_uart_init(DBG_UART_BAUD);

    /* Default: keep debug port enabled for field diagnostics; adjust as policy requires */
    (void)plat_debug_port_config(DBG_PORT_SWD, 1);

    con_banner();
}

void diag_console_poll(void) {
    uint8_t b;
    while (plat_uart_read_byte(&b) == 1) {
        shell_on_rx_char(b);
    }
    con_flush();
}

